export default function TopCategories({ onSelectCategory }: any) {
  const categories = [
    "Electronics",
    "Clothing & Apparel",
    "Home & Kitchen",
    "Beauty & Personal Care",
    "Grocery & Food",
    "Appliances",
    "Health & Wellness",
    "Pet Supplies",
  ];

  return (
    <header className="flex items-center justify-center bg-white border-b border-gray-200 shadow-sm h-14 px-6">
      <nav className="flex items-center gap-6 overflow-x-auto no-scrollbar">
        {categories.map((category) => (
          <button
            key={category}
            onClick={() => onSelectCategory(category)}
            className="hoverable px-4 py-2 text-sm font-medium text-gray-700 rounded-md transition-all duration-200 whitespace-nowrap"
          >
            {category}
          </button>
        ))}
      </nav>
    </header>
  );
}
