import { Tag, Flame, Percent, Store } from "lucide-react";

export default function SideNav() {
  const navItems = [
    { name: "Store Coupons", icon: <Tag size={18} /> },
    { name: "Store Ads", icon: <Percent size={18} /> },
    { name: "Super Hot Deals", icon: <Flame size={18} /> },
    { name: "All Stores", icon: <Store size={18} /> },
  ];

  return (
    <nav className="bg-gray-50 border-r border-gray-200 h-[calc(100vh-120px)] flex flex-col items-center py-3 space-y-3">
      {navItems.map((item) => (
        <div
          key={item.name}
          className="hoverable flex flex-col items-center justify-center w-12 h-12 rounded-md text-gray-600 hover:text-blue-700 transition cursor-pointer"
          title={item.name}
        >
          {item.icon}
        </div>
      ))}
    </nav>
  );
}
